INSERT INTO `movie` VALUES ('149b3ced-9644-4d61-a050-420b1cb0e466',1,'2026-04-08 20:40:20.396000',NULL,'2026-04-08 20:40:20.396981',NULL,_binary '\0',NULL,'C16','Khi thành phố Gotham chìm trong hỗn loạn bởi sự xuất hiện của tên tội phạm tâm thần Joker, Batman phải đối mặt với thử thách lớn nhất trong sự nghiệp anh hùng của mình. Bộ phim là cuộc đấu trí nghẹt thở giữa công lý và sự hỗn loạn, đẩy người hùng vào những lựa chọn đạo đức khắc nghiệt.',110,'DUBBED','https://res.cloudinary.com/dohgdvnuy/image/upload/v1775655506/images/eztxsfnx02qsxdasqj1k.jpg','2026-04-08','the-dark-knight','COMING_SOON','The Dark Knight','https://res.cloudinary.com/dohgdvnuy/video/upload/v1775655525/videos/en8d6xmymjucckt3zyp9.mp4'),('3427643a-f9e1-4f68-a58d-e3a38df455ab',2,'2026-04-08 20:26:36.195203',NULL,'2026-04-08 20:26:52.740283',NULL,_binary '\0',NULL,'P','Tiến sĩ Victor Frankenstein, một nhà khoa học tài giỏi nhưng kiêu ngạo, đã tạo ra một sinh vật trong một thí nghiệm quái dị mà cuối cùng dẫn đến sự diệt vong của cả người tạo ra và sinh vật đáng thương do ông tạo ra.',110,'ORIGINAL','https://res.cloudinary.com/dohgdvnuy/image/upload/v1775654790/images/ote9wbbzhbp6apodp3qh.webp','2026-04-08','frankenstein-2025','NOW_SHOWING','Frankenstein (2025)','https://res.cloudinary.com/dohgdvnuy/video/upload/v1775654765/videos/mqisuoy7xbyqblxpv4cx.mp4'),('3abff416-ff92-49e6-b400-8e57fc47074e',2,'2026-04-08 20:21:59.751085',NULL,'2026-04-08 20:26:56.908599',NULL,_binary '\0',NULL,'C13','Bốn kẻ lạc loài bất ngờ bị kéo qua một cánh cổng bí ẩn vào một thế giới kỳ lạ hình khối, nơi trí tưởng tượng được nuôi dưỡng. Để trở về nhà, họ phải chinh phục thế giới này trong khi bắt đầu một cuộc phiêu lưu cùng một người thợ thủ công lành nghề bất ngờ.',90,'DUBBED','https://res.cloudinary.com/dohgdvnuy/image/upload/v1775654426/images/jk90cb2ziaev3toi0fod.jpg','2026-04-08','minecraft-movie','NOW_SHOWING','Minecraft Movie','https://res.cloudinary.com/dohgdvnuy/video/upload/v1775654447/videos/xvtd2caxqwwy0oh9hyid.mp4'),('473fa2b1-f536-4dd8-8547-52b4cecf96fa',9,'2026-04-06 16:39:14.287746',NULL,'2026-04-08 20:14:20.613316',NULL,_binary '','2026-04-08 20:14:20.611203','C16','Spider-Man 2 là một trong những bộ phim siêu anh hùng kinh điển, tiếp nối hành trình của Peter Parker khi anh phải đối mặt với những thử thách lớn hơn cả về sức mạnh lẫn cuộc sống cá nhân. Nội dung phim xoay quanh việc Peter cố gắng cân bằng giữa trách nhiệm làm Người Nhện và cuộc sống bình thường của một sinh viên nghèo tại New York.\n\nTrong phần này, Peter dần cảm thấy kiệt sức khi phải liên tục cứu người, dẫn đến việc mất đi sức mạnh siêu nhiên của mình. Điều này phản ánh xung đột nội tâm sâu sắc: anh khao khát một cuộc sống bình thường, được ở bên những người mình yêu thương, đặc biệt là Mary Jane. Tuy nhiên, trách nhiệm lớn lao luôn kéo anh trở lại với vai trò của một siêu anh hùng.\n\nSong song đó, một nhân vật phản diện mới xuất hiện – Tiến sĩ Otto Octavius (Doctor Octopus), một nhà khoa học tài năng nhưng bị tha hóa bởi thí nghiệm thất bại. Với những cánh tay cơ khí nguy hiểm, Doc Ock trở thành mối đe dọa lớn cho thành phố và cũng là phép thử cho bản lĩnh của Spider-Man.\n\nĐiểm đặc biệt của phim không chỉ nằm ở các cảnh hành động mãn nhãn mà còn ở chiều sâu tâm lý nhân vật. Peter Parker không phải là một anh hùng hoàn hảo; anh mắc sai lầm, do dự và thậm chí muốn từ bỏ. Nhưng chính điều đó khiến nhân vật trở nên gần gũi và chân thực.\n\nSpider-Man 2 truyền tải thông điệp mạnh mẽ về trách nhiệm, sự hy sinh và lòng dũng cảm. Bộ phim khẳng định rằng trở thành anh hùng không phải là việc có siêu năng lực, mà là lựa chọn đứng lên bảo vệ người khác, ngay cả khi phải đánh đổi rất nhiều.',120,'ORIGINAL','https://res.cloudinary.com/dohgdvnuy/image/upload/v1775493514/images/n2vkf3kmfqbzoilcauww.jpg','2026-04-07','sprider-man-2','COMING_SOON','SPRIDER-MAN-2','https://youtu.be/TcMBFSGVi1c'),('6ff664f3-5d26-4c22-a79d-763f1dcc7f5b',1,'2026-04-08 20:36:35.482093',NULL,'2026-04-08 20:36:35.486910',NULL,_binary '\0',NULL,'C16','Một kẻ trộm bậc thầy chuyên xâm nhập vào giấc mơ của người khác để đánh cắp bí mật công nghệ. Tuy nhiên, nhiệm vụ cuối cùng của anh không phải là lấy đi thông tin, mà là thực hiện một \"khởi nguồn\" — cấy ghép một ý tưởng vào sâu trong tiềm thức. Ranh giới giữa thực tại và ảo mộng chưa bao giờ mong manh đến thế.',110,'ORIGINAL','https://res.cloudinary.com/dohgdvnuy/image/upload/v1775655352/images/rzhtl2t3r1nbnwr3dwd8.jpg','2026-05-14','inception','COMING_SOON','Inception','https://res.cloudinary.com/dohgdvnuy/video/upload/v1775655333/videos/nrzba7yyptzg2vwdyauw.mp4'),('abf2e346-184e-4f9f-98ab-fa8124769ed3',4,'2026-04-04 10:53:17.294600',NULL,'2026-04-08 20:14:22.727105',NULL,_binary '','2026-04-08 20:14:22.725544','C18','ÁMDKASMDKAS',180,'DUBBED','https://res.cloudinary.com/dohgdvnuy/image/upload/v1775299982/images/mvx0tl7swi9lpsl2bmld.jpg','2026-04-04','spiderman','ENDED','SPIDERMAN','https://res.cloudinary.com/dohgdvnuy/video/upload/v1775299992/videos/cs7bnp833nykgikl0u4k.mp4'),('ae2dbb43-42e3-455c-a0b1-e99071dce85c',2,'2026-04-08 20:20:08.681807',NULL,'2026-04-08 20:27:00.534187',NULL,_binary '\0',NULL,'C18','Trong một chuyến thám hiểm không gian của con người, Mickey 17, một nhân viên được coi là \"dùng một lần\", được cử đi khám phá một hành tinh băng giá.',120,'DUBBED','https://res.cloudinary.com/dohgdvnuy/image/upload/v1775654366/images/n1lxriiuglaciued4tqx.png','2026-04-08','mickey-17','NOW_SHOWING','Mickey 17','https://res.cloudinary.com/dohgdvnuy/video/upload/v1775654397/videos/pm961ryqd6b0xjqvefqr.mp4'),('c9dcc703-7775-49b1-9675-b1ba126d4970',3,'2026-04-08 20:24:54.609645',NULL,'2026-04-08 21:48:43.745302',NULL,_binary '','2026-04-08 21:48:43.735320','C16','Một cuốn tiểu sử độc đáo về siêu sao nhạc pop Robbie Williams, ghi lại sự nổi lên như vũ bão, sự sa sút đầy kịch tính và sự hồi sinh đáng kinh ngạc của anh.',120,'ORIGINAL','https://res.cloudinary.com/dohgdvnuy/image/upload/v1775654670/images/secke9x3nog1bqrbfwpc.jpg','2026-04-08','better-man','NOW_SHOWING','Better Man','https://res.cloudinary.com/dohgdvnuy/video/upload/v1775654687/videos/or50emi4wvij1e5urq9v.mp4'),('d1d1cb0a-10c9-4ec2-914f-d0f5190d91eb',1,'2026-04-08 20:31:43.402182',NULL,'2026-04-08 20:31:43.419739',NULL,_binary '\0',NULL,'C16','Chuyến tàu định mệnh khởi hành từ Southampton mang theo câu chuyện tình lãng mạn nhưng đầy bi kịch giữa Jack, một họa sĩ nghèo và Rose, một tiểu thư quý tộc đang bị gông cùm bởi những lễ giáo thượng lưu. Một tình yêu vĩnh cửu nảy nở giữa đại dương mênh mông, ngay trước khi thảm họa kinh hoàng ập đến.',140,'ORIGINAL','https://res.cloudinary.com/dohgdvnuy/image/upload/v1775655081/images/wz8853tf2l1tcc539jqs.png','2026-04-08','titanic','COMING_SOON','Titanic','https://res.cloudinary.com/dohgdvnuy/video/upload/v1775655096/videos/hj0upx0xngjaizleanxv.mp4'),('d645ee7c-6d81-48b8-a988-cd53156b675e',2,'2026-04-08 20:23:29.969214',NULL,'2026-04-08 20:27:09.587100',NULL,_binary '\0',NULL,'C16','Gia đình của Jake và Neytiri phải vật lộn với nỗi đau mất mát, đồng thời chạm trán với một bộ lạc Na\'vi mới hung hăng, bộ lạc Ash People, do thủ lĩnh Varang đầy lửa dẫn đầu, khi cuộc xung đột trên Pandora leo thang và một trọng tâm đạo đức mới nổi lên.',120,'ORIGINAL','https://res.cloudinary.com/dohgdvnuy/image/upload/v1775654538/images/zzfa4vav1fx7ljq1wwij.jpg','2026-04-08','avatar-fire-and-ash','NOW_SHOWING','Avatar Fire and Ash','https://res.cloudinary.com/dohgdvnuy/video/upload/v1775654603/videos/vep9m2kx0wuzmqzspnav.mp4'),('da61a458-59cd-4482-89ec-bf9f065ec223',2,'2026-04-08 22:20:14.647386',NULL,'2026-04-08 22:20:22.614444',NULL,_binary '\0',NULL,'C16','Sau sự kiện hủy diệt tàn khốc, vũ trụ chìm trong cảnh hoang tàn. Với sự trợ giúp của những đồng minh còn sống sót, biệt đội siêu anh hùng Avengers tập hợp một lần nữa để đảo ngược hành động của Thanos và khôi phục lại trật tự của vũ trụ.',120,'ORIGINAL','https://res.cloudinary.com/dohgdvnuy/image/upload/v1775661527/images/ciouta1ibqcnq15lnw70.jpg','2026-04-08','avengers-endgame','NOW_SHOWING','Avengers: Endgame','https://res.cloudinary.com/dohgdvnuy/video/upload/v1775661546/videos/vgmzgqvrhbscdhegekrc.mp4'),('e6294d15-49b4-4375-85ed-1d2fb39fb042',2,'2026-04-08 16:50:10.589841',NULL,'2026-04-08 20:14:18.326681',NULL,_binary '','2026-04-08 20:14:18.321059','C16','Bốn kẻ lạc loài bất ngờ bị kéo qua một cánh cổng bí ẩn vào một thế giới kỳ lạ hình khối, nơi trí tưởng tượng được nuôi dưỡng. Để trở về nhà, họ phải chinh phục thế giới này trong khi bắt đầu một cuộc phiêu lưu cùng một người thợ thủ công lành nghề bất ngờ.',120,'ORIGINAL','https://res.cloudinary.com/dohgdvnuy/image/upload/v1775641707/images/pqtwuqce7tdm1lpulblu.jpg','2026-04-09','-movie','COMING_SOON','Minecraft Movie','https://res.cloudinary.com/dohgdvnuy/video/upload/v1775641739/videos/ytrlf0mvp3jztcxybvj7.mp4'),('f356da2e-eb30-443d-b3a3-8d288c610641',1,'2026-04-08 20:38:13.114402',NULL,'2026-04-08 20:38:13.115950',NULL,_binary '\0',NULL,'C16','Bị kết án tù chung thân vì một tội ác mà mình không hề gây ra, nhân viên ngân hàng Andy Dufresne đã tìm cách thích nghi với cuộc sống khắc nghiệt tại nhà tù Shawshank. Qua nhiều thập kỷ, tình bạn chân thành và niềm hy vọng mãnh liệt đã giúp anh thực hiện một kế hoạch thay đổi số phận không ai ngờ tới.',110,'ORIGINAL','https://res.cloudinary.com/dohgdvnuy/image/upload/v1775655421/images/ui6tnq3ic3xyc8altfri.jpg','2026-06-17','the-shawshank-redemption','COMING_SOON','The Shawshank Redemption','https://res.cloudinary.com/dohgdvnuy/video/upload/v1775655447/videos/gaiyoz6x4v9crkrydawx.mp4');
